// frontend/src/pages/Payment.js
import React, { useContext, useState } from "react";
import { CartContext } from "../context/CartContext";
import { loadStripe } from "@stripe/stripe-js";
import { Elements, CardElement, useStripe, useElements } from "@stripe/react-stripe-js";
import "./Payment.css";

const stripePromise = loadStripe(process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY);

const CheckoutForm = () => {
  const { totalPrice, deliveryInfo } = useContext(CartContext);
  const stripe = useStripe();
  const elements = useElements();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      // 1️⃣ Create payment intent
      const res = await fetch("http://localhost:5000/api/create-payment-intent", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ amount: Math.round(totalPrice * 100) }),
      });
      const data = await res.json();

      const card = elements.getElement(CardElement);
      const result = await stripe.confirmCardPayment(data.clientSecret, { payment_method: { card } });

      if (result.error) setError(result.error.message);
      else {
        setSuccess(true);

        // 2️⃣ Save order to backend
        await fetch("http://localhost:5000/api/orders", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            fullName: deliveryInfo.fullName,
            email: deliveryInfo.email,
            phone: deliveryInfo.phone,
            country: deliveryInfo.country,
            address: deliveryInfo.address,
            totalAmount: totalPrice,
            paymentStatus: "Paid",
            stripePaymentId: result.paymentIntent.id,
          }),
        });
      }
    } catch (err) {
      setError("Payment failed: " + err.message);
    }

    setLoading(false);
  };

  if (success)
    return (
      <div className="payment-success">
        <h2>Payment Successful 🎉</h2>
        <p>Your order has been placed successfully.</p>
      </div>
    );

  return (
    <div className="payment-page">
      {deliveryInfo && (
        <div className="delivery-summary">
          <h3>Delivery Details</h3>
          <p><strong>Name:</strong> {deliveryInfo.fullName}</p>
          <p><strong>Email:</strong> {deliveryInfo.email}</p>
          <p><strong>Phone:</strong> {deliveryInfo.phone}</p>
          <p><strong>Country:</strong> {deliveryInfo.country}</p>
          <p><strong>Address:</strong> {deliveryInfo.address}</p>
        </div>
      )}
      <form className="checkout-form" onSubmit={handleSubmit}>
        <h2>Payment</h2>
        <CardElement className="card-element" />
        {error && <div className="payment-error">{error}</div>}
        <button type="submit" disabled={!stripe || loading}>
          {loading ? "Processing..." : `Pay RM ${totalPrice}`}
        </button>
      </form>
    </div>
  );
};

const Payment = () => (
  <Elements stripe={stripePromise}>
    <CheckoutForm />
  </Elements>
);

export default Payment;
